class Solution {
    public int numberOfSubstrings(String s) {
        int a = 0, b = 0, c = 0, res = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'a') a++;
            if (s.charAt(i) == 'b') b++;
            if (s.charAt(i) == 'c') c++;
            res += (a > 0 && b > 0 && c > 0) ? 1 : 0;
            if (i >= 3) {
                if (s.charAt(i - 3) == 'a') a--;
                if (s.charAt(i - 3) == 'b') b--;
                if (s.charAt(i - 3) == 'c') c--;
            }
        }
        return res;
    }
}
